INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1d891324-8358-47a2-b52f-7f51d26fb7b4',
  '00000000-0000-0000-0000-000000000001',
  $escape$scikit-learn Array API Dispatch — GPU Execution Without Rewriting Your Pipeline$escape$,
  $escape$scikit-learn operates on NumPy arrays, not tensors — but since v1.2, experimental Array API dispatch lets you swap in CuPy arrays for GPU execution without touching estimator code. Enable it globally with `sklearn.set_config(array_api_dispatch=True)`, then pass CuPy arrays directly to any Array API-compliant estimator (`LinearDiscriminantAnalysis`, `PCA`, `LogisticRegression`, and others). Internally, sklearn resolves the active namespace via `sklearn.utils._array_api.get_namespace()` and dispatches matrix multiplications, reductions, and broadcasting operations to whatever library backs your input array. NumPy-style broadcasting applies throughout — shape `(n_samples, 1)` broadcast against `(n_features,)` works identically on CPU and GPU paths. On CPU, sklearn parallelizes via joblib (`n_jobs=-1`); on GPU, the same estimator code hits CUDA kernels through CuPy. Critical caveat: mixing CuPy and NumPy arrays inside a single `Pipeline` silently falls back to CPU. Not all estimators support Array API yet — verify with `get_namespace()` before benchmarking. This is sklearn's device management story: no `.to(device)` calls, no tensor graphs — just array-backend substitution.$escape$,
  $escape$import numpy as np
import sklearn
from sklearn.discriminant_analysis import LinearDiscriminantAnalysis
from sklearn.utils._array_api import get_namespace

sklearn.set_config(array_api_dispatch=True)

try:
    import cupy as cp
    xp = cp
except ImportError:
    xp = np  # transparent CPU fallback

X = xp.random.randn(10_000, 128).astype(xp.float32)
y = xp.random.randint(0, 10, 10_000)

lda = LinearDiscriminantAnalysis()
lda.fit(X, y)

ns, _ = get_namespace(lda.coef_)
print(ns.__name__)  # 'cupy' if GPU active, 'numpy' otherwise$escape$,
