INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '227937c2-3178-4496-97a0-e29492a364fd',
  '00000000-0000-0000-0000-000000000001',
  $escape$scikit-learn Custom Transformers — Building Reusable Pipeline Modules with BaseEstimator$escape$,
  $escape$scikit-learn's MLPClassifier and MLPRegressor are the primary handles for neural architecture control. hidden_layer_sizes=(128, 64, 32) defines a 3-layer network — each tuple element is a layer's neuron count. The activation parameter accepts 'relu', 'tanh', 'logistic', or 'identity'; 'relu' is default and best for most tasks.

For custom modules, scikit-learn's answer is BaseEstimator + TransformerMixin. Subclassing both gives you fit/transform/fit_transform for free, plus full get_params()/set_params() support — meaning your transformer integrates natively with GridSearchCV and Pipeline. Implement fit to compute statistics on training data and return self; implement transform to apply the operation.

The key discipline: never store mutable state on self before calling fit. Anything computed in fit (e.g., self.mean_) is a fitted attribute — suffix it with _ by convention. This keeps clone() and cross-validation safe.

Chaining a custom transformer before an MLPClassifier in a Pipeline ensures the transform is refit correctly on every CV fold, preventing data leakage. This is scikit-learn's composable alternative to defining custom layers in deep learning frameworks.$escape$,
  $escape$from sklearn.base import BaseEstimator, TransformerMixin
from sklearn.pipeline import Pipeline
from sklearn.neural_network import MLPClassifier
import numpy as np

class LogTransformer(BaseEstimator, TransformerMixin):
    def fit(self, X, y=None): return self
    def transform(self, X): return np.log1p(np.abs(X))

pipe = Pipeline([
    ("log", LogTransformer()),
    ("mlp", MLPClassifier(
        hidden_layer_sizes=(128, 64, 32),
        activation="relu",
        max_iter=300
    ))
])
pipe.fit(X_train, y_train)$escape$,
  $escape$python$escape$,
