INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a1c599b8-e102-452d-89a8-0fa362793160',
  '00000000-0000-0000-0000-000000000001',
  $escape$scikit-learn Loss Functions — Picking the Right One and Wiring in a Custom Scorer$escape$,
  $escape$scikit-learn ties loss functions directly to estimator parameters — there's no separate loss object. For SGDClassifier, loss='hinge' gives a linear SVM, loss='log_loss' gives logistic regression, and loss='modified_huber' adds outlier tolerance while still outputting calibrated probabilities. For regression, SGDRegressor(loss='huber', epsilon=0.1) treats residuals within ±epsilon as linear, preventing large outliers from dominating gradient updates — unlike squared_error, which squares every residual.

GradientBoostingRegressor and HistGradientBoostingRegressor expose loss='quantile' (paired with alpha for the quantile level), which is the right choice when error costs are asymmetric or you need prediction intervals. loss='huber' on these estimators blends squared and absolute error, controlled by alpha.

For custom evaluation in GridSearchCV or cross_val_score, wrap any callable with make_scorer(fn, greater_is_better=False). Critically, this only affects model selection — it does not inject a custom training gradient. scikit-learn doesn't expose gradient/hessian hooks the way XGBoost or LightGBM do. If you need a truly custom training loss, subclass BaseEstimator and RegressorMixin and implement fit() with your own gradient loop, or switch to a framework that exposes those hooks natively.$escape$,
  $escape$from sklearn.linear_model import SGDRegressor
from sklearn.ensemble import HistGradientBoostingRegressor
from sklearn.metrics import make_scorer
from sklearn.model_selection import cross_val_score
import numpy as np

# Huber: robust to outliers; epsilon sets the linearity threshold
sgd = SGDRegressor(loss='huber', epsilon=0.15, max_iter=1000)

# Quantile loss: predict the 90th percentile (upper bound estimates)
hgbr = HistGradientBoostingRegressor(loss='quantile', quantile=0.9)

# Custom scorer — wraps any fn for GridSearchCV / cross_val_score
def mape(y_true, y_pred):
    return np.mean(np.abs((y_true - y_pred) / np.clip(np.abs(y_true), 1e-8, None)))

mape_scorer = make_scorer(mape, greater_is_better=False)
# cross_val_score(sgd, X, y, scoring=mape_scorer)$escape$,
  $escape$python$escape$,
