INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '13844eef-8f46-4037-8317-c71b2bf59dd4',
  '00000000-0000-0000-0000-000000000001',
  $escape$scikit-learn + XGBoost — Hyperparameter Tuning and Feature Importance the Right Way$escape$,
  $escape$XGBoost integrates with scikit-learn via `XGBClassifier`/`XGBRegressor`, exposing the full `fit`/`predict` API. The three hyperparameters that move the needle most: `n_estimators` (tree count), `max_depth` (overfitting lever), and `learning_rate` (shrinkage). Use `early_stopping_rounds` to avoid manual tuning of `n_estimators` — pass an `eval_set` and let XGBoost halt when validation loss stops improving.

For systematic search, pair `XGBClassifier` with scikit-learn's `RandomizedSearchCV`. Grid search is wasteful here; random search finds good regions faster across XGBoost's wide hyperparameter space.

Feature importance is exposed via `.feature_importances_` (weight-based by default) or `plot_importance()`. Prefer `importance_type='gain'` — it measures average loss reduction per split, far more meaningful than raw split count. Pass this to a `SelectFromModel` transformer to prune low-signal features before retraining, keeping your pipeline composable and sklearn-native.$escape$,
  $escape$from xgboost import XGBClassifier
from sklearn.model_selection import RandomizedSearchCV, train_test_split
from sklearn.pipeline import Pipeline
from sklearn.feature_selection import SelectFromModel
import numpy as np

X_train, X_val, y_train, y_val = train_test_split(X, y, test_size=0.2)

xgb = XGBClassifier(
    n_estimators=1000,
    early_stopping_rounds=20,
    eval_metric="logloss",
    importance_type="gain",
    random_state=42,
)

param_dist = {
    "max_depth": [3, 5, 7],
    "learning_rate": np.logspace(-3, -1, 20),
    "subsample": [0.6, 0.8, 1.0],
    "colsample_bytree": [0.6, 0.8, 1.0],
}

search = RandomizedSearchCV(xgb, param_dist, n_iter=30, cv=3, scoring="roc_auc", n_jobs=-1)
search.fit(X_train, y_train, eval_set=[(X_val, y_val)], verbose=False)

# prune low-importance features and retrain
selector = SelectFromModel(search.best_estimator_, prefit=True)
X_reduced = selector.transform(X_train)$escape$,
  $escape$python$escape$,
