INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'af7abbe1-3f35-4a51-b197-9641b3f78e9f',
  '00000000-0000-0000-0000-000000000001',
  $escape$scikit-learn + JAX — Supercharging Custom Estimators with jit, grad, and vmap$escape$,
  $escape$scikit-learn's `BaseEstimator` contract (`fit`/`predict`, `coef_` conventions) pairs cleanly with JAX when authoring custom estimators that need gradient-based optimization. JAX's `jit` decorator traces your NumPy-compatible loss function once and compiles it to XLA — subsequent calls skip Python overhead entirely. `grad` returns the exact gradient of any scalar-output function with respect to its first argument, replacing manual `np.gradient` hacks or finite-difference approximations common in custom sklearn optimizers.

`vmap` is where scikit-learn users see the biggest win: instead of looping over samples in `transform` or `predict`, `vmap` vectorizes the operation across the batch dimension automatically, matching sklearn's expectation that `predict(X)` handles all rows simultaneously.

The critical integration point: JAX arrays are not sklearn-compatible by default. Wrap inputs with `jnp.array()` inside `fit`/`transform`, and return `np.asarray(result)` at the boundary so downstream sklearn pipeline steps (`Pipeline`, `cross_val_score`) receive plain NumPy. XLA compilation triggers on first call and caches — warm runs on a 10k-row dataset are typically 10–50x faster than equivalent NumPy loops.$escape$,
  $escape$import jax
import jax.numpy as jnp
import numpy as np
from sklearn.base import BaseEstimator, RegressorMixin

@jax.jit
def _mse_loss(params, X, y):
    return jnp.mean((X @ params - y) ** 2)

_grad_loss = jax.grad(_mse_loss)

class JaxLinearRegressor(BaseEstimator, RegressorMixin):
    def fit(self, X, y):
        params = jnp.zeros(X.shape[1])
        for _ in range(300):
            params -= 0.01 * _grad_loss(params, jnp.array(X), jnp.array(y))
        self.coef_ = np.asarray(params)
        return self

    def predict(self, X):
        return np.asarray(jnp.array(X) @ jnp.array(self.coef_))$escape$,
  $escape$python$escape$,
