INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '843f8047-e147-4866-9d22-be3abe5c7e54',
  '00000000-0000-0000-0000-000000000001',
  $escape$scikit-learn + Keras via SciKeras — Plugging Functional API Models into sklearn Pipelines$escape$,
  $escape$scikit-learn's pipeline ecosystem becomes far more powerful once you can slot a deep learning model into it. `scikeras` (the official sklearn-compatible Keras wrapper) does exactly that via `KerasClassifier` and `KerasRegressor`.

The key architectural decision is functional vs sequential inside the builder function. Sequential works for simple stacks, but the functional API unlocks multi-input heads and shared layers — and `scikeras` handles both identically since it only cares about the callable you pass to `model=`.

Any hyperparameter defined in your builder (e.g., `hidden_units`, `learning_rate`) automatically surfaces as a first-class sklearn parameter. That means `GridSearchCV` and `RandomizedSearchCV` can tune them directly — no adapter code needed.

For custom training loops via subclassed models, `scikeras` internally calls `model.fit()`, so overriding it works as long as you preserve the standard Keras `fit` signature. This keeps sklearn's `cross_val_score`, `Pipeline`, and preprocessing steps fully intact alongside your custom gradient logic.$escape$,
  $escape$from scikeras.wrappers import KerasClassifier
from tensorflow import keras
from sklearn.pipeline import Pipeline
from sklearn.preprocessing import StandardScaler
from sklearn.model_selection import GridSearchCV

def build_model(hidden_units=64, learning_rate=1e-3):
    inp = keras.Input(shape=(20,))
    x = keras.layers.Dense(hidden_units, activation="relu")(inp)
    out = keras.layers.Dense(1, activation="sigmoid")(x)
    model = keras.Model(inp, out)
    model.compile(optimizer=keras.optimizers.Adam(learning_rate), loss="binary_crossentropy")
    return model

clf = KerasClassifier(model=build_model, hidden_units=64, epochs=20, verbose=0)
pipe = Pipeline([("scaler", StandardScaler()), ("model", clf)])

grid = GridSearchCV(pipe, {"model__hidden_units": [32, 64, 128]}, cv=3)
grid.fit(X_train, y_train)$escape$,
  $escape$python$escape$,
